import React from "react";
import PropTypes from 'prop-types';
import Head from 'next/head';

const NodeBird = ({ Componet }) => {
    return (
        <>
            <Head>
                <meta charSet="utf-8" />
                <title>NodeBird</title>
            </Head>
            <Component />        
        </>
    );
};

NodeBird.propTpes = {
    Component: PropTypes.elementType.isRequired,
}

export default NodeBird;
